UPDATE APT_DETAIL
SET HO_STTS_CD = 'STRUCT_REMOVED'
WHERE HO_NO = #{hoNo}

UPDATE APT_DETAIL
SET HO_STTS_CD = 'EMPTY'
WHERE HO_NO = #{hoNo}

UPDATE APT_COMPLEX
SET UNIT_CNT = (
    SELECT  COUNT(*)
    FROM    APT_DETAIL
    WHERE   APT_CMPLEX_NO = #{aptCmplexNo}
      AND   HO_STTS_CD IN (
                         'LIVE',
                         'EMPTY'
                        )
)
WHERE APT_CMPLEX_NO = #{aptCmplexNo}

UPDATE APT_COMPLEX
SET MAX_FLOOR = (
    SELECT MAX(D.FLOOR)
    FROM APT_DETAIL D
             JOIN APT_UNIT U
                  ON D.DONG_NO = U.DONG_NO
    WHERE U.APT_CMPLEX_NO = #{aptCmplexNo}
      AND D.HO_STTS_CD != 'STRUCT_REMOVED'
)
WHERE APT_CMPLEX_NO = #{aptCmplexNo}

UPDATE APT_DETAIL
SET HO_STTS_CD = #{hoSttsCd}
WHERE HO_NO IN


    #{hoNo}

UPDATE APT_DETAIL

SET HO_TY_NO = #{hoTyNo}

WHERE HO_NO IN


    #{hoNo}

UPDATE  APT_UNIT
SET     DONG_NM = #{dongNm}
WHERE   DONG_NO = #{dongNo}
